import requests
import json
from langflow.custom import Component
from langflow.io import MessageTextInput, Output
from langflow.schema.message import Message

class ConstructorYEjecutorAPI(Component):
    display_name = "Constructor y Ejecutor API"
    description = "Paso 2: Genera prompts técnicos y descriptivos (sin narrativa)."
    icon = "code"

    inputs = [
        MessageTextInput(
            name="prompt_simple", 
            display_name="Tu Prompt Simple", 
            info="Ejemplo: 'white f40 on a beach'"
        ),
    ]

    outputs = [
        Output(display_name="JSON Bruto de Respuesta", name="json_bruto", method="ejecutar_llamada"),
    ]

    def ejecutar_llamada(self) -> Message:
        url = "https://gen.pollinations.ai/v1/chat/completions"
        
        # IMPORTANTE: Reemplaza YOUR_API_KEY_HERE por tu clave real de Pollinations
        headers = {
            "Authorization": "Bearer YOUR_API_KEY_HERE",
            "Content-Type": "application/json"
        }
        
        # Ajuste del sistema para evitar lo poético y priorizar lo útil/técnico
        payload = {
            "model": "gemini-fast",
            "messages": [
                {
                    "role": "system",
                    "content": (
                        "Eres un ingeniero de prompts técnico especializado en fotografía cinematográfica de alta gama. "
                        "TU MISIÓN: Crear descripciones visuales para generadores de imágenes 4k. "
                        "ESTILO: No uses lenguaje poético, narrativo ni introducciones literarias. Evita metáforas. "
                        "MÉTODO: Describe de forma objetiva y clara: materiales, texturas, tipo de iluminación "
                        "(focal length, aperture, lighting setup), composición de cámara y paleta de colores. "
                        "REGLA CRÍTICA: Devuelve ÚNICAMENTE el prompt técnico resultante. "
                        "Nada de charlas, nada de 'aquí tienes', solo los parámetros visuales crudos y claros."
                    )
                },
                {
                    "role": "user",
                    "content": self.prompt_simple
                }
            ],
            "temperature": 0.8
        }

        try:
            res = requests.post(url, headers=headers, json=payload)
            res.raise_for_status()
            return Message(text=res.text)
            
        except Exception as error:
            return Message(text=f"Error en la llamada: {str(error)}")

import json
from langflow.custom import Component
from langflow.io import MessageTextInput, Output
from langflow.schema.message import Message

class ParserRespuestaPro(Component):
    display_name = "Parser de Respuesta Pro"
    description = "Extrae el texto y metadatos del JSON de Pollinations."
    icon = "braces"

    inputs = [
        MessageTextInput(
            name="json_entrada", 
            display_name="JSON Bruto de Entrada", 
            info="Conecta aquí la salida del nodo que hace la llamada"
        ),
    ]

    outputs = [
        Output(display_name="Prompt Generado", name="prompt_texto", method="extraer_prompt"),
        Output(display_name="Uso de Tokens", name="tokens", method="extraer_tokens"),
        Output(display_name="ID de la Petición", name="request_id", method="extraer_id"),
    ]

    def extraer_prompt(self) -> Message:
        try:
            data = json.loads(self.json_entrada)
            # Ruta: choices -> primer elemento [0] -> message -> content
            texto = data["choices"][0]["message"]["content"]
            return Message(text=texto)
        except Exception as e:
            return Message(text=f"Error al extraer texto: {e}")

    def extraer_tokens(self) -> Message:
        try:
            data = json.loads(self.json_entrada)
            # Ruta: usage -> total_tokens
            total = data["usage"]["total_tokens"]
            prompt = data["usage"]["prompt_tokens"]
            comp = data["usage"]["completion_tokens"]
            return Message(text=f"Total: {total} (Prompt: {prompt}, Generación: {comp})")
        except:
            return Message(text="No se encontraron datos de tokens")

    def extraer_id(self) -> Message:
        try:
            data = json.loads(self.json_entrada)
            # Ruta: campo 'id' en la raíz
            return Message(text=data["id"])
        except:
            return Message(text="ID no encontrado")
